#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline ll read()
{
	ll x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(ll x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MOD=1e9+7;
ll n,m;
void solve()
{
    n=read();
    m=read();
    if(n==1)
    {
        cout<<0<<'\n';
        return;;
    }
    while(n&(n-1))
    {
        n&=n-1;
    }
    m=m/2*(m-m/2);
    write((n*2-1)%MOD*(m)%MOD);
    putchar('\n');
}
int main(void)
{
   for(int t=read();t;--t)
   {
       solve();
   }
   return false;
}
